const body = $json.body || $json;

let sender = body?.whatsappInboundMessage?.from || body?.from || '';
// Text
let message = body?.whatsappInboundMessage?.text?.body || body?.text?.body;

// Interactive (List/Button response)
if (!message && body?.whatsappInboundMessage?.interactive) {
  const interact = body.whatsappInboundMessage.interactive;
  message = interact.list_reply?.title || interact.button_reply?.title || interact.list_reply?.id || interact.button_reply?.id;
}

// Fallback
message = message || 'Hola';
let name = body?.whatsappInboundMessage?.customerProfile?.name || 'Cliente';

return {
  sender: String(sender).trim(),
  message: String(message).trim(),
  name: String(name).trim(),
  shop_slug: 'demo'
};

const msg = $json.message.toLowerCase();
const now = new Date();
const pad = n => String(n).padStart(2,'0');
const iso = d => `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;

let parsed_date = null;

if (msg.includes('mañana')) parsed_date = iso(new Date(now.setDate(now.getDate()+1)));

const m1 = msg.match(/\b(el|para)\s+(\d{1,2})\b/);
if (!parsed_date && m1) {
  const d = new Date();
  d.setDate(Number(m1[2]));
  if (d < new Date()) d.setMonth(d.getMonth()+1);
  parsed_date = iso(d);
}

return { ...$json, parsed_date };

const ctx = Array.isArray($json) ? $json[0] : $json;
const split = x => x ? x.split(',').map(s=>s.trim()) : [];

return {
  shop_name: ctx.shop_name,
  services: split(ctx.services),
  professionals: split(ctx.professionals),
  history: ctx.history || ''
};

const s = Array.isArray($json) ? $json[0] : $json;
return {
  phone: s.phone,
  service: s.service,
  professional: s.professional,
  preferred_date: s.preferred_date,
  preferred_time: s.preferred_time
};

// Lee datos de otros nodos de forma segura (esto sí funciona en Code node)
const msg = String($items("Extract Message")[0]?.json?.message ?? "").toLowerCase();
const sender = String($items("Extract Message")[0]?.json?.sender ?? "").trim();

const ctx = $items("Normalize Context")[0]?.json ?? {};
const session = $items("Normalize Session")[0]?.json ?? {};

// servicios/profesionales pueden venir como array o string
const services = Array.isArray(ctx.services)
  ? ctx.services
  : String(ctx.services ?? "").split(",").map(s => s.trim()).filter(Boolean);

const professionals = Array.isArray(ctx.professionals)
  ? ctx.professionals
  : String(ctx.professionals ?? "").split(",").map(s => s.trim()).filter(Boolean);

// Detectar servicio por "contiene"
let service = null;
for (const s of services) {
  const sKey = s.toLowerCase().split("(")[0].trim(); // "Barba y Perfilado"
  if (sKey && msg.includes(sKey)) {
    service = sKey; 
    break;
  }
}

// Detectar profesional por nombre completo o primer nombre
let professional = null;
for (const p of professionals) {
  const pLower = p.toLowerCase();
  const first = pLower.split(" ")[0]; // joaquin, maria
  if ((pLower && msg.includes(pLower)) || (first && msg.includes(first))) {
    professional = p;
    break;
  }
}

// Fecha parseada desde tu nodo Parse Date (si existe)
const parsedDate = $items("Parse Date")[0]?.json?.parsed_date ?? null;

// Detectar Hora (Nuevo)
let extractedTime = null;
// Matches: "10:30", "10:00", "9:00", "09:00"
const timeMatch1 = msg.match(/\b(\d{1,2}):(\d{2})\b/);
if (timeMatch1) {
  extractedTime = `${timeMatch1[1].padStart(2, '0')}:${timeMatch1[2]}:00`;
} else {
  // Matches: "a las 9", "a las 10"
  const timeMatch2 = msg.match(/\ba\s+las?\s+(\d{1,2})\b/);
  if (timeMatch2) {
    extractedTime = `${timeMatch2[1].padStart(2, '0')}:00:00`;
  }
}

// Merge: NO pises con null lo que ya tenías en sesión
return {
  phone: sender || session.phone || null,
  service: service || session.service || null,
  professional: professional || session.professional || null,
  preferred_date: parsedDate || session.preferred_date || null,
  preferred_time: extractedTime || session.preferred_time || null,
};

