// Input: { output: "text" } OR { output: "##LISTA## { "title": "...", "rows": [...] }" }
const output = $json.output || $json.text || $json.message || '';
const marker = '##LISTA##';

if (output.includes(marker)) {
  try {
    // Extract JSON
    const jsonStr = output.split(marker)[1].trim();
    // Support both simple array (legacy) and object (new)
    let data = JSON.parse(jsonStr);
    let title = 'Opciones';
    let rows = [];

    if (Array.isArray(data)) {
      // Legacy: Array of strings (Time Slots)
      title = 'Horarios Disponibles';
      rows = data;
    } else {
      // New: Object { title, rows }
      title = data.title || 'Opciones';
      rows = data.rows || [];
    }

    // Limits: Max 10 rows for WhatsApp List
    const listRows = rows.slice(0, 10).map((item, i) => ({
      id: item,
      title: item.slice(0, 24),
      description: ''
    }));

    return {
      type: 'interactive',
      interactive: {
        type: 'list',
        header: {
          type: 'text',
          text: title
        },
        body: {
          text: 'Seleccioná una opción:'
        },
        footer: {
          text: 'Asistente Virtual'
        },
        action: {
          button: 'Ver Opciones',
          sections: [
            {
              title: 'Opciones',
              rows: listRows
            }
          ]
        }
      }
    };
  } catch (e) {
    return { type: 'text', text: { body: output + ' [Error JSON]' } };
  }
}

// Default Text
return { type: 'text', text: { body: output } };
